import math

def gaussian_pdf(x, mu, sigma):
    # 连续变量要用密度，不是直接概率
    coeff = 1.0 / math.sqrt(2 * math.pi * sigma * sigma)
    exponent = -((x - mu) ** 2) / (2 * sigma * sigma)
    return coeff * math.exp(exponent)

def bernoulli_pmf(x, p):
    # x 只能是 0 或 1，分别对应失败和成功
    return (p ** x) * ((1 - p) ** (1 - x))

def categorical_pmf(k, probs):
    # 单标签多分类时，第 k 类的概率就是该类质量
    return probs[k]

print(round(gaussian_pdf(0, 0, 1), 4))
print(bernoulli_pmf(1, 0.3))
print(categorical_pmf(0, [0.7, 0.2, 0.1]))

import math

def entropy(probs):
    # 只累加非零概率，避免 log(0)
    return -sum(p * math.log(p) for p in probs if p > 0)

def kl_divergence(p, q):
    # KL 衡量用 q 近似 p 的额外代价
    return sum(pi * math.log(pi / qi) for pi, qi in zip(p, q) if pi > 0 and qi > 0)

def cross_entropy(p, q):
    # 交叉熵直接看真实分布在模型分布下的编码成本
    return -sum(pi * math.log(qi) for pi, qi in zip(p, q) if pi > 0 and qi > 0)

P = [1.0, 0.0]
Q = [0.9, 0.1]
print(round(entropy(P), 4))
print(round(kl_divergence(P, Q), 4))
print(round(cross_entropy(P, Q), 4))
